/**
 * Image similarity search example using placeholder CLIP-style embeddings.
 *
 * In a real pipeline, replace the `embeddingStore` vectors with embeddings
 * generated by CLIP, SigLIP, OpenAI vision embeddings, or another image model.
 */

const { FaissIndex, normalizeVectors } = require('../src/js');

const dims = 8;
const catalog = [
  { id: 'sunrise.jpg', embedding: [0.91, 0.07, 0.11, 0.21, 0.55, 0.13, 0.09, 0.18] },
  { id: 'forest.jpg', embedding: [0.10, 0.88, 0.14, 0.27, 0.22, 0.11, 0.49, 0.17] },
  { id: 'city.jpg', embedding: [0.44, 0.12, 0.83, 0.61, 0.08, 0.52, 0.19, 0.31] },
];

async function main() {
  const index = new FaissIndex({ type: 'FLAT_IP', dims });
  const flattened = new Float32Array(catalog.flatMap((item) => item.embedding));
  await index.add(normalizeVectors(flattened, dims));

  const query = normalizeVectors(new Float32Array([
    0.87, 0.08, 0.15, 0.25, 0.51, 0.16, 0.10, 0.20,
  ]), dims);

  const results = await index.search(query, 2);
  const matches = Array.from(results.labels).map((label, i) => ({
    file: catalog[label]?.id,
    score: Number(results.distances[i].toFixed(4)),
  }));

  console.log(matches);
}

main().catch((error) => {
  console.error(error);
  process.exitCode = 1;
});
